final:
module shift_register (
    input clk,
    input shift,
    input [3:0] D,
    output reg Q3
);

reg [3:0] reg_data;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (shift == 1'b0) begin
        reg_data <= D;
    end else begin
        reg_data <= {reg_data[2:0], D[3]};
    end
end

assign Q3 = reg_data[3];

endmodule
